void editorSetStatusMessage(const char *fmt, ...);

/* =========================== Syntax highlights DB =========================
 *
 * In order to add a new syntax, define two arrays with a list of file name
 * matches and keywords. The file name matches are used in order to match
 * a given syntax with a given file name: if a match pattern starts with a
 * dot, it is matched as the last past of the filename, for example ".c".
 * Otherwise the pattern is just searched inside the filenme, like "Makefile").
 *
 * The list of keywords to highlight is just a list of words, however if they
 * a trailing '|' character is added at the end, they are highlighted in
 * a different color, so that you can have two different sets of keywords.
 *
 * Finally add a stanza in the HLDB global variable with two two arrays
 * of strings, and a set of flags in order to enable highlighting of
 * comments and numbers.
 *
 * The characters for single and multi line comments must be exactly two
 * and must be provided as well (see the C language example).
 *
 * There is no support to highlight patterns currently. */

/* C / C++ */
char *C_HL_extensions[] = {".c",".h",".cpp",".hpp",".cc",NULL};
char *C_HL_keywords[] = {
	/* C Keywords */
	"auto","break","case","continue","default","do","else","enum",
	"extern","for","goto","if","register","return","sizeof","static",
	"struct","switch","typedef","union","volatile","while","NULL",

	/* C++ Keywords */
	"alignas","alignof","and","and_eq","asm","bitand","bitor","class",
	"compl","constexpr","const_cast","deltype","delete","dynamic_cast",
	"explicit","export","false","friend","inline","mutable","namespace",
	"new","noexcept","not","not_eq","nullptr","operator","or","or_eq",
	"private","protected","public","reinterpret_cast","static_assert",
	"static_cast","template","this","thread_local","throw","true","try",
	"typeid","typename","virtual","xor","xor_eq",

	/* C types */
        "int|","long|","double|","float|","char|","unsigned|","signed|",
        "void|","short|","auto|","const|","bool|",NULL
};

/* Here we define an array of syntax highlights by extensions, keywords,
 * comments delimiters and flags. */
struct editorSyntax HLDB[] = {
    {
        /* C / C++ */
        C_HL_extensions,
        C_HL_keywords,
        "//","/*","*/",
        HL_HIGHLIGHT_STRINGS | HL_HIGHLIGHT_NUMBERS
    }
};

#define HLDB_ENTRIES (sizeof(HLDB)/sizeof(HLDB[0]))

/* ======================= Low level terminal handling ====================== */

static struct termios orig_termios; /* In order to restore at exit.*/

void disableRawMode(int fd) {
    /* Don't even check the return value as it's too late. */
    if (E.rawmode) {
        tcsetattr(fd,TCSAFLUSH,&orig_termios);
        E.rawmode = 0;
    }
}

/* Called at exit to avoid remaining in raw mode. */
void editorAtExit(void) {
    disableRawMode(STDIN_FILENO);
}

/* Scripted terminal-syscall return codes supplied by the CBMC models in
 * stubs/rawmode.c: rm_isatty is isatty()'s result, rm_tcget tcgetattr()'s and
 * rm_tcset tcsetattr()'s.  They make enableRawMode's outcome a deterministic
 * function of these globals so the contract below can pin it exactly.
 * Referenced only by the contract; a normal build needs no definition. */
extern int rm_isatty;
extern int rm_tcget;
extern int rm_tcset;
extern int rm_errno; /* the object behind errno; see stubs/rawmode.c */

/* Raw mode: 1960 magic shit. */
int enableRawMode(int fd)
    /* Verify the not-yet-enabled path (the early "already enabled" return is a
     * trivial no-op outside the mutated branches). */
    __CPROVER_requires(E.rawmode == 0)
    __CPROVER_assigns(E.rawmode, rm_errno)
    __CPROVER_ensures(__CPROVER_return_value == 0 || __CPROVER_return_value == -1)
    /* Success (return 0, raw mode now on) happens exactly when the terminal is a
     * tty and both tcgetattr() and tcsetattr() succeed; any other combination
     * takes the fatal path.  Pinning this exact relationship to the three
     * scripted return codes kills every comparison-operator mutant on the
     * tcgetattr()/tcsetattr() error checks. */
    __CPROVER_ensures((__CPROVER_return_value == 0) ==
        (rm_isatty != 0 && rm_tcget != -1 && rm_tcset >= 0))
    __CPROVER_ensures((E.rawmode == 1) == (__CPROVER_return_value == 0))
    /* The fatal path always reports ENOTTY (rm_errno is the errno object). */
    __CPROVER_ensures(__CPROVER_return_value == -1 ==> rm_errno == ENOTTY)
{
    struct termios raw;

    if (E.rawmode) return 0; /* Already enabled. */
    if (!isatty(STDIN_FILENO)) goto fatal;
    atexit(editorAtExit);
    if (tcgetattr(fd,&orig_termios) == -1) goto fatal;

    raw = orig_termios;  /* modify the original mode */
    /* input modes: no break, no CR to NL, no parity check, no strip char,
     * no start/stop output control. */
    raw.c_iflag &= ~(BRKINT | ICRNL | INPCK | ISTRIP | IXON);
    /* output modes - disable post processing */
    raw.c_oflag &= ~(OPOST);
    /* control modes - set 8 bit chars */
    raw.c_cflag |= (CS8);
    /* local modes - choing off, canonical off, no extended functions,
     * no signal chars (^Z,^C) */
    raw.c_lflag &= ~(ECHO | ICANON | IEXTEN | ISIG);
    /* control chars - set return condition: min number of bytes and timer. */
    raw.c_cc[VMIN] = 0; /* Return each byte, or zero for timeout. */
    raw.c_cc[VTIME] = 1; /* 100 ms timeout (unit is tens of second). */

    /* put terminal in raw mode after flushing */
    if (tcsetattr(fd,TCSAFLUSH,&raw) < 0) goto fatal;
    E.rawmode = 1;
    return 0;

fatal:
    errno = ENOTTY;
    return -1;
}

/* Scripted-input globals supplied by the CBMC read()/exit() models (see
 * stubs/readkey.c).  rk_ret<i> is the return value of the i-th read() (-1, 0 or
 * 1) and rk_byte<i> the byte it delivers; rk_idx is the next read index.  They
 * are referenced only by editorReadKey's contract below and are otherwise
 * unused, so a normal build needs no definition. */
extern int  rk_idx;
extern int  rk_ret[6];
extern char rk_byte[6];

/* Read a key from the terminal put in raw mode, trying to handle
 * escape sequences. */
int editorReadKey(int fd)
    /* Start of the scripted input. */
    __CPROVER_requires(rk_idx == 0)
