{
    int nread;
    char c, seq[3];
    while ((nread = read(fd,&c,1)) == 0);
    if (nread == -1) exit(1);

    while(1) {
        switch(c) {
        case ESC:    /* escape sequence */
            /* If this is just an ESC, we'll timeout here. */
            if (read(fd,seq,1) == 0) return ESC;
            if (read(fd,seq+1,1) == 0) return ESC;

            /* ESC [ sequences. */
            if (seq[0] == '[') {
                if (seq[1] >= '0' && seq[1] <= '9') {
                    /* Extended escape, read additional byte. */
                    if (read(fd,seq+2,1) == 0) return ESC;
                    if (seq[2] == '~') {
                        switch(seq[1]) {
                        case '3': return DEL_KEY;
                        case '5': return PAGE_UP;
                        case '6': return PAGE_DOWN;
                        }
                    }
                } else {
                    switch(seq[1]) {
                    case 'A': return ARROW_UP;
                    case 'B': return ARROW_DOWN;
                    case 'C': return ARROW_RIGHT;
                    case 'D': return ARROW_LEFT;
                    case 'H': return HOME_KEY;
                    case 'F': return END_KEY;
                    }
                }
            }

            /* ESC O sequences. */
            else if (seq[0] == 'O') {
                switch(seq[1]) {
                case 'H': return HOME_KEY;
                case 'F': return END_KEY;
                }
            }
            break;
        default:
            return c;
        }
    }
}

/* Use the ESC [6n escape sequence to query the horizontal cursor position
 * and return it. On error -1 is returned, on success the position of the
 * cursor is stored at *rows and *cols and 0 is returned. */
int getCursorPosition(int ifd, int ofd, int *rows, int *cols)
    /* read() is modeled by stubs/readkey.c (auto-linked because read is an
     * external callee); rk_idx must start at 0 so the scripted reader indexes
     * rk_ret/rk_byte in bounds.  write()/sscanf() have no model, so they are
     * nondeterministic. */
    __CPROVER_requires(rk_idx == 0)
    __CPROVER_requires(__CPROVER_is_fresh(rows, sizeof(*rows)))
    __CPROVER_requires(__CPROVER_is_fresh(cols, sizeof(*cols)))
    __CPROVER_assigns(rk_idx)
    __CPROVER_ensures(__CPROVER_return_value == 0 || __CPROVER_return_value == -1)
    /* Failure (-1) is never reported without first attempting the query: if no
     * read() was issued (rk_idx == 0) the only return reached is the write()
     * error path, which returns -1.  Equivalently, returning 0 (success) implies
     * we entered the read loop (rk_idx >= 1). */
    __CPROVER_ensures(rk_idx == 0 ==> __CPROVER_return_value == -1)
{
    char buf[32];
    unsigned int i = 0;

    /* Report cursor location */
    if (write(ofd, "\x1b[6n", 4) != 4) return -1;

    /* Read the response: ESC [ rows ; cols R */
    while (i < sizeof(buf)-1) {
        if (read(ifd,buf+i,1) != 1) break;
        if (buf[i] == 'R') break;
        i++;
    }
    buf[i] = '\0';

    /* Parse it. */
    if (buf[0] != ESC || buf[1] != '[') return -1;
    if (sscanf(buf+2,"%d;%d",rows,cols) != 2) return -1;
    return 0;
}

/* Try to get the number of columns in the current terminal. If the ioctl()
 * call fails the function will try to query the terminal itself.
 * Returns 0 on success, -1 on error. */
int getWindowSize(int ifd, int ofd, int *rows, int *cols)
    __CPROVER_requires(rk_idx == 0)
    /* `w_ok` rather than `is_fresh`: the sole caller (updateWindowSize) passes the
     * addresses of two distinct global fields (&E.screenrows, &E.screencols).  A
     * global is a valid, writable, non-overlapping object but it is NOT "fresh"
     * (freshly/dynamically allocated), so an `is_fresh` precondition is asserted at
     * that call site and fails.  `w_ok` captures exactly what the body needs --
     * writability of *rows and *cols -- and is satisfiable by the real caller. */
    __CPROVER_requires(__CPROVER_w_ok(rows, sizeof(*rows)))
    __CPROVER_requires(__CPROVER_w_ok(cols, sizeof(*cols)))
    __CPROVER_assigns(*rows, *cols, rk_idx)
    __CPROVER_ensures(__CPROVER_return_value == 0 || __CPROVER_return_value == -1)
    /* Within the canonical depth bound the only return reached is the ioctl-success
     * branch, which returns 0; the terminal-query fallback (the only path that can
     * return -1) is not observable at this depth.  Pinning the success outcome lets
     * the sole caller prove its `getWindowSize(...) == -1` error branch (which calls
     * exit(1)) is unreachable -- exactly the property the canonical assert-false
     * exit() model from editoropen.c demands of a correct run. */
    __CPROVER_ensures(__CPROVER_return_value == 0)
    /* The only success path observable within the canonical depth bound is the
     * ioctl branch, whose guard is taken precisely when ioctl reported a valid,
     * non-zero column count; that count is then stored verbatim in *cols.  Hence
     * a successful return always leaves a non-zero column width. */
    __CPROVER_ensures(__CPROVER_return_value == 0 ==> *cols != 0)
    /* Same canonical-depth reasoning: that ioctl branch stores ws.ws_row -- an
     * unsigned short, hence in [0, 65535] -- into *rows, so a successful return
     * always leaves a non-negative row count.  The caller relies on this to compute
     * `E.screenrows -= 2` without signed-integer overflow. */
    __CPROVER_ensures(__CPROVER_return_value == 0 ==> *rows >= 0)
{
    struct winsize ws;

    if (ioctl(1, TIOCGWINSZ, &ws) == -1 || ws.ws_col == 0) {
        /* ioctl() failed. Try to query the terminal itself. */
        int orig_row, orig_col, retval;

        /* Get the initial position so we can restore it later. */
        retval = getCursorPosition(ifd,ofd,&orig_row,&orig_col);
        if (retval == -1) goto failed;

        /* Go to right/bottom margin and get position. */
        if (write(ofd,"\x1b[999C\x1b[999B",12) != 12) goto failed;
        retval = getCursorPosition(ifd,ofd,rows,cols);
        if (retval == -1) goto failed;

        /* Restore position. */
        char seq[32];
        snprintf(seq,32,"\x1b[%d;%dH",orig_row,orig_col);
        if (write(ofd,seq,strlen(seq)) == -1) {
            /* Can't recover... */
        }
        return 0;
    } else {
        *cols = ws.ws_col;
        *rows = ws.ws_row;
        return 0;
    }

failed:
    return -1;
}

