     * recursive propagation and the previous-row lookup in the original, while
     * leaving E.row a valid one-element array so that the off-by-one neighbour
     * accesses introduced by mutants (E.row[-1], E.row[numrows]) are caught as
     * out-of-bounds. */
    __CPROVER_requires(row->idx == 0)
    __CPROVER_requires(E.numrows == 1)
    __CPROVER_requires(__CPROVER_is_fresh(E.row, sizeof(erow)))
    /* A syntax definition with an empty (NULL-terminated) keyword list. */
    __CPROVER_requires(__CPROVER_is_fresh(E.syntax, sizeof(*E.syntax)))
    __CPROVER_requires(__CPROVER_is_fresh(E.syntax->keywords, sizeof(char *)))
    __CPROVER_requires(E.syntax->keywords[0] == NULL)
    __CPROVER_assigns(row->hl, __CPROVER_object_whole(row->hl), row->hl_oc)
    /* On return hl is a valid rsize-byte buffer. */
    __CPROVER_ensures(row->hl != NULL)
{
    row->hl = realloc(row->hl,row->rsize);
    memset(row->hl,HL_NORMAL,row->rsize);

    if (E.syntax == NULL) return; /* No syntax, everything is HL_NORMAL. */

    int i, prev_sep, in_string, in_comment;
    char *p;
    char **keywords = E.syntax->keywords;
    char *scs = E.syntax->singleline_comment_start;
    char *mcs = E.syntax->multiline_comment_start;
    char *mce = E.syntax->multiline_comment_end;

    /* Point to the first non-space char. */
    p = row->render;
    i = 0; /* Current char offset */
    while(*p && isspace(*p)) {
        p++;
        i++;
    }
    prev_sep = 1; /* Tell the parser if 'i' points to start of word. */
    in_string = 0; /* Are we inside "" or '' ? */
    in_comment = 0; /* Are we inside multi-line comment? */

    /* If the previous line has an open comment, this line starts
     * with an open comment state. */
    if (row->idx > 0 && editorRowHasOpenComment(&E.row[row->idx-1]))
        in_comment = 1;

    while(*p) {
        /* Handle // comments. */
        if (prev_sep && *p == scs[0] && *(p+1) == scs[1]) {
            /* From here to end is a comment */
            memset(row->hl+i,HL_COMMENT,row->size-i);
            return;
        }

        /* Handle multi line comments. */
        if (in_comment) {
            row->hl[i] = HL_MLCOMMENT;
            if (*p == mce[0] && *(p+1) == mce[1]) {
                row->hl[i+1] = HL_MLCOMMENT;
                p += 2; i += 2;
                in_comment = 0;
                prev_sep = 1;
                continue;
            } else {
                prev_sep = 0;
                p++; i++;
                continue;
            }
        } else if (*p == mcs[0] && *(p+1) != mcs[1]) {
            row->hl[i] = HL_MLCOMMENT;
            row->hl[i+1] = HL_MLCOMMENT;
            p += 2; i += 2;
            in_comment = 1;
            prev_sep = 0;
            continue;
        }

        /* Handle "" and '' */
        if (in_string) {
            row->hl[i] = HL_STRING;
            if (*p == '\\') {
                row->hl[i+1] = HL_STRING;
                p += 2; i += 2;
                prev_sep = 0;
                continue;
            }
            if (*p == in_string) in_string = 0;
            p++; i++;
            continue;
        } else {
            if (*p == '"' || *p == '\'') {
                in_string = *p;
                row->hl[i] = HL_STRING;
                p++; i++;
                prev_sep = 0;
                continue;
            }
        }

        /* Handle non printable chars. */
        if (!isprint(*p)) {
            row->hl[i] = HL_NONPRINT;
            p++; i++;
            prev_sep = 0;
            continue;
        }

        /* Handle numbers */
        if ((isdigit(*p) && (prev_sep || row->hl[i-1] == HL_NUMBER)) ||
            (*p == '.' && i >0 && row->hl[i-1] == HL_NUMBER)) {
            row->hl[i] = HL_NUMBER;
            p++; i++;
            prev_sep = 0;
            continue;
        }

        /* Handle keywords and lib calls */
        if (prev_sep) {
            int j;
            for (j = 0; keywords[j]; j++) {
                int klen = strlen(keywords[j]);
                int kw2 = keywords[j][klen-1] == '|';
                if (kw2) klen--;

                if (!memcmp(p,keywords[j],klen) &&
                    is_separator(*(p+klen)))
                {
                    /* Keyword */
                    memset(row->hl+i,kw2 ? HL_KEYWORD2 : HL_KEYWORD1,klen);
                    p += klen;
                    i += klen;
                    break;
                }
            }
            if (keywords[j] != NULL) {
                prev_sep = 0;
                continue; /* We had a keyword match */
            }
        }

        /* Not special chars */
        prev_sep = is_separator(*p);
        p++; i++;
    }

    /* Propagate syntax change to the next row if the open commen
     * state changed. This may recursively affect all the following rows
     * in the file. */
    int oc = editorRowHasOpenComment(row);
    if (row->hl_oc != oc && row->idx+1 < E.numrows)
        editorUpdateSyntax(&E.row[row->idx+1]);
    row->hl_oc = oc;
}

/* Maps syntax highlight token types to terminal colors. */
int editorSyntaxToColor(int hl)
__CPROVER_assigns()
__CPROVER_ensures((hl == HL_COMMENT || hl == HL_MLCOMMENT) ==> __CPROVER_return_value == 36)
__CPROVER_ensures(hl == HL_KEYWORD1 ==> __CPROVER_return_value == 33)
__CPROVER_ensures(hl == HL_KEYWORD2 ==> __CPROVER_return_value == 32)
__CPROVER_ensures(hl == HL_STRING ==> __CPROVER_return_value == 35)
__CPROVER_ensures(hl == HL_NUMBER ==> __CPROVER_return_value == 31)
__CPROVER_ensures(hl == HL_MATCH ==> __CPROVER_return_value == 34)
__CPROVER_ensures((hl != HL_COMMENT && hl != HL_MLCOMMENT && hl != HL_KEYWORD1 &&
                   hl != HL_KEYWORD2 && hl != HL_STRING && hl != HL_NUMBER &&
                   hl != HL_MATCH) ==> __CPROVER_return_value == 37)
{
    switch(hl) {
    case HL_COMMENT:
    case HL_MLCOMMENT: return 36;     /* cyan */
    case HL_KEYWORD1: return 33;    /* yellow */
    case HL_KEYWORD2: return 32;    /* green */
    case HL_STRING: return 35;      /* magenta */
    case HL_NUMBER: return 31;      /* red */
    case HL_MATCH: return 34;      /* blu */
    default: return 37;             /* white */
    }
}

/* Select the syntax highlight scheme depending on the filename,
 * setting it in the global state E.syntax. */
void editorSelectSyntaxHighlight(char *filename)
    /* `filename` is a tight, bounds-tracked, NUL-terminated buffer (2 content
     * bytes + trailing NUL).  The concrete capacity keeps every strstr/strlen
     * access bounds-checked and makes the match outcome a finite function of a
     * few bytes, which is what lets the postcondition pin E.syntax exactly.  Two
     * content bytes is the shortest filename that exposes both a match at the end
     * of the string and a match in the middle (the case that distinguishes the
     * real end-of-string test, p[patlen]=='\0', from a mutant that drops it). */
    __CPROVER_requires(__CPROVER_is_fresh(filename, 3))
    __CPROVER_requires(filename[2] == '\0')
    /* A genuinely non-empty filename: an empty string matches nothing and would
     * collapse the case analysis below. */
    __CPROVER_requires(filename[0] != '\0')
    /* Contract enforcement havocs all globals, so HLDB (and the extension list it
     * points at) start nondeterministic.  Pin HLDB[0].filematch to a concrete,
     * fully bounds-tracked shape: a 2-slot, NUL-terminated list holding exactly
     * one single-character pattern.  A 1-char pattern makes strstr's result a
     * function of two byte comparisons (does the char occur, and where), so the
     * selection outcome is expressible exactly while still exercising the
     * strstr / end-of-string / dot-prefix / `||` logic. */
    __CPROVER_requires(__CPROVER_is_fresh(HLDB[0].filematch, 2 * sizeof(char *)))
    __CPROVER_requires(HLDB[0].filematch[1] == NULL)
    __CPROVER_requires(__CPROVER_is_fresh(HLDB[0].filematch[0], 2))
    __CPROVER_requires(HLDB[0].filematch[0][1] == '\0')
    /* A non-empty pattern; strstr of the empty string always matches at position
     * 0 and would not exercise the search. */
    __CPROVER_requires(HLDB[0].filematch[0][0] != '\0')
    /* Start from "no syntax selected" so the postcondition can pin E.syntax
     * exactly: it is either left at NULL or set to the sole HLDB entry. */
    __CPROVER_requires(E.syntax == NULL)
    /* The function's only side effect is selecting (or not) the syntax entry. */
    __CPROVER_assigns(E.syntax)
    /* Exact characterization of the selection.  Let P = filematch[0][0] be the
     * single pattern character (P != '\0').  strstr finds P at the first position
     * it occurs; the code then selects iff (P != '.') OR that occurrence ends the
     * string (p[patlen] == '\0').  Over a 2-byte filename f0 f1:
     *   - f0 == P: occurrence at 0, ends the string iff f1 == '\0';
     *   - f0 != P && f1 == P: occurrence at 1, always ends the string.
     * Pinning E.syntax to exactly this condition kills mutants that flip the
     * strstr test, the end-of-string test, the dot-prefix test, the `||`, the
     * loop bound, or that skip the loop entirely. */
    __CPROVER_ensures(
        ( (filename[0] == HLDB[0].filematch[0][0] &&
           (HLDB[0].filematch[0][0] != '.' || filename[1] == '\0')) ||
          (filename[0] != HLDB[0].filematch[0][0] &&
           filename[1] == HLDB[0].filematch[0][0]) )
        ? (E.syntax == HLDB)
        : (E.syntax == NULL))
{
    for (unsigned int j = 0; j < HLDB_ENTRIES; j++) {
        struct editorSyntax *s = HLDB+j;
        unsigned int i = 0;
        while(s->filematch[i]) {
            char *p;
            int patlen = strlen(s->filematch[i]);
            if ((p = strstr(filename,s->filematch[i])) != NULL) {
                if (s->filematch[i][0] != '.' || p[patlen] == '\0') {
                    E.syntax = s;
                    return;
                }
            }

